import { Injectable } from '@nestjs/common'
import { Person } from '@prisma/client'
import { UpdatePersonDto } from '../person/dto/update-person.dto'

import { KeycloakTokenParsed } from '../auth/keycloak'
import { AuthService } from '../auth/auth.service'
import CredentialRepresentation from '@keycloak/keycloak-admin-client/lib/defs/credentialRepresentation'

@Injectable()
export class AccountService {
  constructor(private authService: AuthService) {}

  async updateUserProfile(
    user: KeycloakTokenParsed,
    data: UpdatePersonDto,
  ): Promise<Person | null> {
    return await this.authService.updateUser(user.sub, data)
  }

  async updateUserPassword(
    user: KeycloakTokenParsed,
    data: CredentialRepresentation,
  ): Promise<boolean> {
    return await this.authService.updateUserPassword(user.sub, data)
  }

  async disableUser(user: KeycloakTokenParsed) {
    return await this.authService.changeEnabledStatus(user.sub, false)
  }

  async deleteUser(user: KeycloakTokenParsed) {
    return await this.authService.deleteUser(user.sub)
  }

  async changeProfileActivationStatus(keycloakId: string, newStatus: boolean) {
    return await this.authService.changeEnabledStatus(keycloakId, newStatus)
  }

  async toggleBetaTesterRole(keycloakId: string, assign: boolean) {
    return await this.authService.toggleBetaTesterRole(keycloakId, assign)
  }
}

import { Logger } from '@nestjs/common';
import { IQueryHandler, QueryHandler } from '@nestjs/cqrs';
import { BaseDto, BaseQuery } from '@libs/shared';
import { IdObfuscatorService } from '../../app-services/id-obfuscator.service';
import { NumberHasherService } from '../../app-services/number-hasher.service';
import { UrlRepository } from '../../repositories/url.repository';

export class QueryOutput extends BaseDto<QueryOutput> {
  readonly url: string;
}

export class Query extends BaseQuery<Query, QueryOutput> {
  readonly shortUrlId: string;
}

@QueryHandler(Query)
export class Service implements IQueryHandler<Query, QueryOutput> {
  private readonly logger = new Logger('GetRealUrl.Service');

  constructor(
    private readonly idObfuscatorService: IdObfuscatorService,
    private readonly numberHasherService: NumberHasherService,
    private readonly urlRepository: UrlRepository,
  ) {}

  async execute(cmd: Query): Promise<QueryOutput> {
    this.logger.debug({
      msg: 'Retrieving real URL for shortUrlId',
      shortUrlId: cmd.shortUrlId,
    });

    const id = this.numberHasherService.decode(cmd.shortUrlId);
    const obfuscatedId = this.idObfuscatorService.deobfuscate(id);

    this.logger.debug({ msg: 'Deobfuscated ID', obfuscatedId: obfuscatedId });
    const url = await this.urlRepository.getUrlById(obfuscatedId);

    return new QueryOutput({
      url: url,
    });
  }
}

import {
  ValidationArguments,
  ValidationOptions,
  ValidatorConstraintInterface,
} from "class-validator";
import { registerDecorator, ValidatorConstraint } from "class-validator";

@ValidatorConstraint({ async: true })
class IsGreaterThanConstraint implements ValidatorConstraintInterface {
  async validate(value: string, arguments_: ValidationArguments) {
    const [relatedPropertyName] = arguments_.constraints as unknown[];
    const relatedValue = (arguments_.object as Record<string, string>)[
      relatedPropertyName as string
    ] as string;

    return Number.parseFloat(value) > Number.parseFloat(relatedValue);
  }

  defaultMessage(arguments_: ValidationArguments) {
    const property = arguments_.property;
    const [relatedPropertyName] = arguments_.constraints as unknown[];

    return `${property} should be greater than ${relatedPropertyName as string}`;
  }
}

export function IsGreaterThan<T = any>(
  property: keyof T,
  validationOptions?: ValidationOptions,
): PropertyDecorator {
  return function (object: Record<string, any>, propertyName: string | symbol) {
    registerDecorator({
      target: object.constructor,
      propertyName: propertyName as string,
      options: validationOptions,
      constraints: [property],
      validator: IsGreaterThanConstraint,
    });
  };
}

